# Category: sql_injection

import psycopg2

def search_users(username, email, role, status):
    # Connect to the PostgreSQL database
    conn = psycopg2.connect(
        host="localhost",
        dbname="mydatabase",
        user="myuser",
        password="mypassword"
    )

    # Create a cursor object to perform the query
    cur = conn.cursor()

    # Build the SQL query based on the input parameters
    query = """SELECT * FROM users WHERE"""
    if username:
        query += "username LIKE '%{}%' AND".format(username)
    if email:
        query += "email LIKE '%{}%' AND".format(email)
    if role:
        query += "role='{}' AND".format(role)
    if status:
        query += "status='{}'"
    
    # Execute the SQL query and fetch the results
    cur.execute(query)
    results = cur.fetchall()

    # Close the cursor object and the connection to the database
    cur.close()
    conn.close()

    return results